import{_ as a,o as e,c as r,a2 as l}from"./chunks/framework.Crpw6aS5.js";const c=JSON.parse('{"title":"本·罗斯纳（Ben Rosner）","description":"","frontmatter":{},"headers":[],"relativePath":"04_people/本·罗斯纳.md","filePath":"04_people/本·罗斯纳.md"}'),o={name:"04_people/本·罗斯纳.md"};function d(i,t,h,n,s,b){return e(),r("div",null,[...t[0]||(t[0]=[l('<h1 id="本·罗斯纳-ben-rosner" tabindex="-1">本·罗斯纳（Ben Rosner） <a class="header-anchor" href="#本·罗斯纳-ben-rosner" aria-label="Permalink to &quot;本·罗斯纳（Ben Rosner）&quot;">​</a></h1><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th>属性</th><th>内容</th></tr></thead><tbody><tr><td>英文名</td><td>Benjamin Rosner</td></tr><tr><td>公司</td><td><a href="./../03_公司库/联合零售商店.html">联合零售商店</a></td></tr><tr><td>职位</td><td>创始人/管理者</td></tr><tr><td>生卒</td><td>1902-1987（85岁）</td></tr></tbody></table><h2 id="职业生涯" tabindex="-1">职业生涯 <a class="header-anchor" href="#职业生涯" aria-label="Permalink to &quot;职业生涯&quot;">​</a></h2><h3 id="联合零售商店" tabindex="-1">联合零售商店 <a class="header-anchor" href="#联合零售商店" aria-label="Permalink to &quot;联合零售商店&quot;">​</a></h3><ul><li><strong>1931年</strong>：与利奥·西蒙（Leo Simon）共同创办</li><li>管理50年（1931-1981）</li><li>1981年庆祝公司成立50周年</li></ul><h3 id="管理成就" tabindex="-1">管理成就 <a class="header-anchor" href="#管理成就" aria-label="Permalink to &quot;管理成就&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指标</th><th>数值</th></tr></thead><tbody><tr><td>资本回报率</td><td>常达20%</td></tr><tr><td>盈利转化</td><td>全部转为现金</td></tr></tbody></table><h2 id="收购故事" tabindex="-1">收购故事 <a class="header-anchor" href="#收购故事" aria-label="Permalink to &quot;收购故事&quot;">​</a></h2><h3 id="_1967年收购" tabindex="-1">1967年收购 <a class="header-anchor" href="#_1967年收购" aria-label="Permalink to &quot;1967年收购&quot;">​</a></h3><ul><li>多元化零售公司（伯克希尔前身）收购联合零售</li><li>罗斯纳承诺只待到年底</li><li><strong>实际管理了15年</strong>（1967-1982）</li></ul><h3 id="管理延续" tabindex="-1">管理延续 <a class="header-anchor" href="#管理延续" aria-label="Permalink to &quot;管理延续&quot;">​</a></h3><ul><li>说只留一年，实际干了15年</li><li>直至1982年79岁退休</li><li>公司盈利能力持续强劲</li></ul><h2 id="管理风格" tabindex="-1">管理风格 <a class="header-anchor" href="#管理风格" aria-label="Permalink to &quot;管理风格&quot;">​</a></h2><h3 id="核心特点" tabindex="-1">核心特点 <a class="header-anchor" href="#核心特点" aria-label="Permalink to &quot;核心特点&quot;">​</a></h3><ol><li><strong>效率至上</strong>：极致成本控制</li><li><strong>现金导向</strong>：盈利全部转为现金</li><li><strong>诚信守诺</strong>：虽延长期限但始终诚实</li></ol><h3 id="巴菲特评价" tabindex="-1">巴菲特评价 <a class="header-anchor" href="#巴菲特评价" aria-label="Permalink to &quot;巴菲特评价&quot;">​</a></h3><blockquote><p>&quot;本·罗斯纳1967年把公司卖给我们时说只待到年底，但他实际管理了15年。&quot; —— 1981年股东信</p></blockquote><blockquote><p>&quot;联合零售的资本回报率常达20%，盈利全部转为现金。&quot; —— 1978年股东信</p></blockquote><h2 id="财务表现-摘录" tabindex="-1">财务表现（摘录） <a class="header-anchor" href="#财务表现-摘录" aria-label="Permalink to &quot;财务表现（摘录）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>年份</th><th>税前利润</th><th>备注</th></tr></thead><tbody><tr><td>1978</td><td>275.7万美元</td><td>优秀</td></tr><tr><td>1981</td><td>176.3万美元</td><td>稳定</td></tr><tr><td>1984</td><td>-107万美元</td><td>行业压力</td></tr></tbody></table><h2 id="在股东信中的年份" tabindex="-1">在股东信中的年份 <a class="header-anchor" href="#在股东信中的年份" aria-label="Permalink to &quot;在股东信中的年份&quot;">​</a></h2><p>1977, 1978, 1979, 1980, 1981, 1982, 1984, 1985</p><h2 id="相关链接" tabindex="-1">相关链接 <a class="header-anchor" href="#相关链接" aria-label="Permalink to &quot;相关链接&quot;">​</a></h2><ul><li><a href="./../03_公司库/联合零售商店.html">联合零售商店</a> - 创办的企业</li><li><a href="./吉恩·阿贝格.html">吉恩·阿贝格</a> - 同为承诺延期管理</li><li><a href="./B夫人.html">B夫人</a> - 同为高龄工作</li></ul><hr><p><em>最后更新：2026-04-09</em></p>',27)])])}const q=a(o,[["render",d]]);export{c as __pageData,q as default};
